function luhnAlgorithm(cardNumber) {
    const cardNumberArray = cardNumber.split('').reverse().map(digit => parseInt(digit, 10));
    let checksum = 0;

    cardNumberArray.forEach((digit, index) => {
        if (index % 2 === 1) {
            digit *= 2;
            if (digit > 9) digit -= 9;
        }
        checksum += digit;
    });

    return checksum % 10 === 0;
}

